def _de_normalize_translation_text(_s):
    try:
        if not isinstance(_s, str):
            return _s
        for _a, _b in _DE_EXTRA_033:
            if _a in _s:
                _s = _s.replace(_a, _b)
        # light whitespace cleanup after phrase substitutions
        _s = _s.replace("  ", " ").replace(" :", ":")
        return _s
    except Exception:
        return _s

